class RateLimiter:
    """Simple in-memory rate limiter using sliding window."""

    def __init__(self, window_seconds, max_requests):
        self._window = window_seconds
        self._max_requests = max_requests
        self._requests = {}  # key -> list of timestamps

    def is_allowed(self, key):
        """Check if a request from the given key is allowed."""
        now = time.monotonic()
        if key not in self._requests:
            self._requests[key] = []

        # Remove expired entries
        self._requests[key] = [
            ts for ts in self._requests[key]
            if now - ts < self._window
        ]

        if len(self._requests[key]) >= self._max_requests:
            return False

        self._requests[key].append(now)
        return True

    def cleanup(self):
        """Remove stale entries to prevent memory growth."""
        now = time.monotonic()
        stale_keys = [
            key for key, timestamps in self._requests.items()
            if not timestamps or now - max(timestamps) > self._window * 2
        ]
        for key in stale_keys:
            del self._requests[key]


def _sanitize_header_value(value):
    """Sanitize header value to prevent header injection."""
    if not isinstance(value, str):
        value = str(value)
    # Remove newlines and carriage returns to prevent header injection
    value = value.replace('\r', '').replace('\n', '').replace('\0', '')
    # Truncate overly long values
