def _load_tls_credentials():
    """Load TLS credentials for the gRPC server."""
    if not TLS_CERT_PATH or not TLS_KEY_PATH:
        return None

    try:
        with open(TLS_KEY_PATH, 'rb') as f:
            private_key = f.read()
        with open(TLS_CERT_PATH, 'rb') as f:
            certificate_chain = f.read()

        root_certificates = None
        if TLS_CA_CERT_PATH:
            with open(TLS_CA_CERT_PATH, 'rb') as f:
                root_certificates = f.read()

        credentials = grpc.ssl_server_credentials(
            [(private_key, certificate_chain)],
            root_certificates=root_certificates,
            require_client_auth=bool(root_certificates),
        )
        return credentials
    except (IOError, OSError) as e:
        logger.error("Failed to load TLS credentials: %s", str(e))
        raise


def serve():
    """Start the gRPC authorization server."""
    # Validate port
    try:
        port = int(GRPC_PORT)
        if port < 1 or port > 65535:
            raise ValueError("Port out of range")
    except ValueError:
        logger.error("Invalid GRPC_PORT: %s", GRPC_PORT)
        raise SystemExit(1)

    if not AUTH_SECRET_KEY and not ALLOWED_API_KEYS:
        logger.warning(
            "Neither AUTH_SECRET_KEY nor ALLOWED_API_KEYS is configured. "
            "All authenticated requests will be denied."
        )

    if AUTH_SECRET_KEY and len(AUTH_SECRET_KEY) < 32:
        logger.warning("AUTH_SECRET_KEY is shorter than recommended minimum of 32 characters")

    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=GRPC_MAX_WORKERS),
        options=[
            ('grpc.max_receive_message_length', 1024 * 1024),  # 1MB max
            ('grpc.max_send_message_length', 1024 * 1024),  # 1MB max
            ('grpc.keepalive_time_ms', 30000),
            ('grpc.keepalive_timeout_ms', 10000),
            ('grpc.keepalive_permit_without_calls', False),
            ('grpc.max_connection_idle_ms', 300000),
        ],
    )

    auth_service = AuthorizationService()
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(auth_service, server)

    tls_credentials = _load_tls_credentials()

    listen_address = "[::]:%d" % port

    if tls_credentials:
        server.add_secure_port(listen_address, tls_credentials)
        logger.info("Starting secure gRPC auth server on %s", listen_address)
    else:
        logger.warning(
            "Starting INSECURE gRPC auth server on %s. "
            "Set TLS_CERT_PATH and TLS_KEY_PATH for production use.",
            listen_address
        )
        server.add_insecure_port(listen_address)

    server.start()
    logger.info("Envoy External Authorization service is running on port %d", port)

    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        logger.info("Shutting down authorization server...")
        server.stop(grace=5)
        logger.info("Server stopped.")


if __name__ == "__main__":
    serve()